var baseReviewInclude = {
  gearItem: true,
  customer: {
    omit: { password: true }
  }
};
var ReviewsService = class {
  async getReview(id) {
    const review = await prisma.reviews.findUnique({
      where: { id },
      include: baseReviewInclude
    });
    if (!review) throw new ApiError(httpStatus16.NOT_FOUND, "Review not found.");
    return review;
  }
  validateRating(rating) {
    if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
      throw new ApiError(httpStatus16.BAD_REQUEST, "Rating must be an integer between 1 and 5.");
    }
  }
  validateComment(comment) {
    if (comment === void 0) return null;
    const trimmedComment = comment.trim();
    if (!trimmedComment) return null;
    if (trimmedComment.length > 500) {
      throw new ApiError(httpStatus16.BAD_REQUEST, "Comment must be 500 characters or fewer.");
    }
    return trimmedComment;
  }
  async getAllReviews(user) {
    let whereCondition = {};
    if (user.role === Role.PROVIDER) {
      whereCondition = { gearItem: { providerId: user.id } };
    } else if (user.role === Role.CUSTOMER) {
      whereCondition = { customerId: user.id };
    }
    return prisma.reviews.findMany({
      where: whereCondition,
      include: baseReviewInclude
    });
  }
  async getSingleReview(user, id) {
    const review = await this.getReview(id);
    const hasAccess = user.role === Role.ADMIN || user.role === Role.PROVIDER && review.gearItem.providerId === user.id || user.role === Role.CUSTOMER && review.customerId === user.id;
    if (!hasAccess) {
      throw new ApiError(httpStatus16.FORBIDDEN, "Forbidden: You do not have access to this review.");
    }
    return review;
  }
  async createReview(user, payload) {
    const { gearItemId, rating, comment } = payload;
    if (!gearItemId) throw new ApiError(httpStatus16.BAD_REQUEST, "gearItemId is required.");
    this.validateRating(Number(rating));
    const normalizedComment = this.validateComment(comment);
    const gearItem = await Promise.all([
      prisma.gearItems.findUnique({ where: { id: gearItemId } })
    ]);
    if (!gearItem) throw new ApiError(httpStatus16.NOT_FOUND, "Gear item not found.");
    return prisma.reviews.create({
      data: {
        customerId: user.id,
        gearItemId,
        rating: Number(rating),
        comment: normalizedComment
      },
      include: baseReviewInclude
    });
  }
  async updateReview(user, id, payload) {
    const review = await this.getReview(id);
    const updates = {};
    if (user.id !== review.customerId) {
      throw new ApiError(httpStatus16.FORBIDDEN, "Forbidden: Only review owner can update this reviews.");
    }
    if (payload.rating !== void 0) {
      this.validateRating(Number(payload.rating));
      updates.rating = Number(payload.rating);
    }
    if (payload.comment !== void 0) {
      updates.comment = this.validateComment(payload.comment);
    }
    if (Object.keys(updates).length === 0) {
      throw new ApiError(httpStatus16.BAD_REQUEST, "No valid fields were provided for update.");
    }
    return prisma.reviews.update({
      where: { id: review.id },
      data: updates,
      include: baseReviewInclude
    });
  }
  async deleteReview(user, id) {
    if (user.role !== Role.ADMIN) {
      throw new ApiError(httpStatus16.FORBIDDEN, "Forbidden: Only providers and admins can delete reviews.");
    }
    const review = await this.getReview(id);
    return prisma.reviews.delete({ where: { id: review.id } });
  }
};
